var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"제기랄......","JPN":"畜生ォ……","ENG":"Damn it...","TWN":"可惡……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"제기랄! 제기랄! 제기랄! 제기랄! 제기랄! 제기랄! 제기랄!","JPN":"畜生ォ！　畜生ォ！　畜生ォ！　畜生ォ！　畜生ォ！\\n畜生ォ！　畜生ォ！","ENG":"Damn it! Damn it! Damn it! Damn it! Damn it! Damn it! Damn it!","TWN":"可惡！可惡！可惡！可惡！可惡！可惡！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"사도랍시고 무게는 있는 대로 잡더니 겨우 한 명에게 박살 나 버려?!","JPN":"使徒だからってあんなに威張り散らしておいて、\\nたった一人に撃破されたの！？","ENG":"She went all Shakespeare on us with her Apostle talk, only to let one Closer smash her to bits like that?","TWN":"什麼破使徒，竟然被一個人打爆了？！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"저딴 걸 믿은 내가 멍청이였지!","JPN":"あんなのを頼りにした私がバカだったわ！","ENG":"I'm the fool for relying on something like that!","TWN":"會相信這種東西的我是個笨蛋！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"날 처박아 둔 곳까지 도망쳐 오다니...... 꽤나 급해진 모양이군, 알렉스?","JPN":"こんなところに放り捨ててくれたと思えば、また逃げ戻ってくるとは……\\nよほど切羽詰まってるようだな？　アレックス。","ENG":"So you've fled all the way to where you've stashed me... Looks like you're getting desperate, Alex.","TWN":"妳竟然逃到了關我的地方……看起來妳也被逼急了呢，雅蕾克絲？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"닥쳐! 애초에 네가 저런 쭉정이와 계약한 게 문제였어!","JPN":"黙りなさい！　そもそもアンタがあんなでくの坊と契約を交わしたのが間違いなのよ！","ENG":"Shut up! You should have never signed a deal with a good-for-nothing loser like that!","TWN":"閉嘴！說到底，都怪妳和那個垃圾定契約！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"그 녀석이 죽어버렸으니 너도 끈 떨어진 건 마찬가지야!","JPN":"あいつが死んでしまった以上、\\nもうアンタも拠り所がなくなったのは同じだわ！","ENG":"You're screwed too, since she's dead now!","TWN":"那傢伙現在已經死了，沒有人可以幫妳撐腰了！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"사도급 이상의 침식체는 불멸의 존재다.","JPN":"使徒以上の侵食体は不滅の存在だ。","ENG":"Apostles and any other C.O.s beyond them are immortal.","TWN":"使徒級以上的侵蝕體是不滅的存在。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"이수연에게 육체를 파괴당하고 클리파 너머로 추방당했지만, 언젠가 힘을 회복해서 다시 돌아오겠지.","JPN":"カナミ・キズナに肉体を破壊され、クリファ次元の彼方へ\\n追放されようと、いつか力を回復してまた戻ってくる。","ENG":"Although her flesh may have been destroyed by Lee Sooyeon and banished beyond the Qlipha, she will recover and return one day.","TWN":"雖然它的肉體被李秀妍破壞，放逐回了逆卡巴拉，但總有一天，它會恢復力量回來的。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"계약자인 우리 얘기는 지금도 다 듣고 있을 텐데, 조금은 말조심을 해야 할 것 같지 않나?","JPN":"契約者である我々の発言は今でもすべて筒抜けのはずだ。\\n少しは口を慎むべきだと思わないか？","ENG":"She's probably listening in on contractors like us even now. Perhaps you should choose your words more carefully.","TWN":"她現在應該還在聽我們契約者的對話，妳說話最好還是小心一點喔？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"그, 그건...... 그러니까 내 말뜻은 그게 아니라......","JPN":"えっ、その……だから、私が言ったのはそういう意味じゃ……","ENG":"Th-that's... Well, I didn't mean it like that...","TWN":"這、這……所以說，我想說的不是那樣……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"오해하지 마! 그런 뜻은 아니었어!","JPN":"誤解しないでよ！　別に悪気があったわけじゃないの！","ENG":"I hope there's no misunderstanding! I didn't mean it like that!","TWN":"別誤會！我不是那個意思！"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"그러니까 그 분께는 오해하지 말라고 전달을 좀......","JPN":"だからあの方が誤解なさらないように、あなたの方から話を……","ENG":"So, um, could you tell her that I didn't really mean that?","TWN":"妳能不能替我解釋一下，讓他不要誤會……"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"흥. 알겠다. 그 정도야.","JPN":"フン。いいだろう。それくらいなら容易い。","ENG":"Hmpf. Fine. That shouldn't be too hard.","TWN":"哼，好啦，我會啦。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_REAL","text":{"KOREA":"저, 정말이야?","JPN":"ほ、本当？","ENG":"R-really?","TWN":"真、真的嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_REAL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"그래. 어차피 나도 살아남으려면 도움이 필요하니까.","JPN":"ああ。私とて生き残るためには助力が必要だからな。","ENG":"Yes. I need your help to survive anyways.","TWN":"對，畢竟我想活命，也需要妳的幫忙。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"사도께서 패퇴하긴 했어도 클리파의 봉인이 약해진 건 변하지 않아.","JPN":"使徒が敗退されたとはいえ、\\nクリファ次元の封印は今も弱まったままだ。","ENG":"Although the Apostle has been defeated, the Qlipha's seal remains weakened.","TWN":"雖然使徒大人戰敗了，但逆卡巴拉的封印變弱的事實也沒有改變。"},"stage":{"bg":"COUNTERSIDE_SNOW","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};